<template><SiteLayout><section class="mx-auto max-w-4xl px-4 py-14"><p class="font-black uppercase tracking-[0.25em] text-emerald-700">Bots Integration</p><h1 class="mt-4 text-4xl font-black">Cybersecurity FAQ Bot</h1><p class="mt-3 text-slate-600">Demo bot for WhatsApp, Telegram, and web chat. Every question is logged in the backend.</p><div class="mt-6 flex gap-3"><a class="rounded bg-emerald-700 px-4 py-3 font-bold text-white" href="https://wa.me/233505313578">Chat with us on WhatsApp</a><a class="rounded bg-sky-600 px-4 py-3 font-bold text-white" href="https://t.me/YoungCyberKnightsBot">Chat with us on Telegram</a></div><div class="mt-8 rounded border bg-white p-5"><div class="max-h-80 space-y-3 overflow-auto"><div v-for="item in messages" :key="item.id" :class="item.role==='user'?'text-right':''"><span class="inline-block rounded px-4 py-2" :class="item.role==='user'?'bg-emerald-700 text-white':'bg-slate-100 text-slate-800'">{{ item.text }}</span></div></div><form class="mt-5 flex gap-2" @submit.prevent="send"><input v-model="message" class="flex-1 rounded border p-3" placeholder="Ask about phishing, passwords, hacked account..."><button class="rounded bg-slate-950 px-5 font-bold text-white">Send</button></form><p v-if="error" class="mt-3 text-red-600">{{ error }}</p></div></section></SiteLayout></template>
<script setup lang="ts">import { ref } from 'vue';import SiteLayout from '../components/SiteLayout.vue';import { askBot } from '../services/botService';const message=ref('');const error=ref('');const messages=ref([{id:1,role:'bot',text:'Hi, I am the YCKF cyber FAQ bot. Ask me about phishing, passwords, hacked accounts, certificates, or premium training.'}]);async function send(){if(!message.value.trim())return;const text=message.value;messages.value.push({id:Date.now(),role:'user',text});message.value='';try{const response=await askBot(text,'web');messages.value.push({id:Date.now()+1,role:'bot',text:response})}catch(e:any){error.value=e.message||'Bot unavailable'}}</script>
